import{_ as a,c as n,a1 as s,o as t}from"./chunks/framework.DiyHpDmR.js";const h=JSON.parse('{"title":"当前主线","description":"","frontmatter":{},"headers":[],"relativePath":"intro/mainline.md","filePath":"intro/mainline.md","lastUpdated":1783292246000}'),o={name:"intro/mainline.md"};function i(c,e,l,d,p,r){return t(),n("div",null,e[0]||(e[0]=[s(`<h1 id="当前主线" tabindex="-1">当前主线 <a class="header-anchor" href="#当前主线" aria-label="Permalink to &quot;当前主线&quot;">​</a></h1><p>本文概括 Firefly 官方文档当前采用的实现基线。更细的设计材料来自 <code>backend/design/current</code> 文档，落地事实以各 Firefly 仓库当前代码为准。</p><h2 id="版本基线" tabindex="-1">版本基线 <a class="header-anchor" href="#版本基线" aria-label="Permalink to &quot;版本基线&quot;">​</a></h2><p>Go 业务服务模板当前主线是：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>go-layout v0.3.5</span></span>
<span class="line"><span>go-micro v1.6.4</span></span>
<span class="line"><span>go-consul v0.3.6</span></span></code></pre></div><p>控制面组件 <code>sidecar-agent</code> 与 <code>api-gateway</code> 当前直接依赖 <code>go-micro v1.6.4</code>。它们分别通过本机 admin API、Envoy xDS 和 Consul HTTP API 承接控制面事实，不直接引入 <code>go-consul</code>。</p><p><code>api-gateway</code>、<code>authz</code> 等独立组件可能处于不同依赖版本，阅读文档时不要把 Go 业务服务模板的版本号直接套到所有仓库。官方指南会在组件页说明各自职责和运行入口。</p><h2 id="主链路" tabindex="-1">主链路 <a class="header-anchor" href="#主链路" aria-label="Permalink to &quot;主链路&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>业务 proto</span></span>
<span class="line"><span>  -&gt; buf generate</span></span>
<span class="line"><span>  -&gt; dep/protobuf/gen/gateway.manifest.json</span></span>
<span class="line"><span>  -&gt; go-consul/agent</span></span>
<span class="line"><span>  -&gt; sidecar-agent</span></span>
<span class="line"><span>  -&gt; Consul service 与 route document</span></span>
<span class="line"><span>  -&gt; api-gateway / sidecar-agent 编译 Envoy xDS</span></span>
<span class="line"><span>  -&gt; Envoy ext_authz 调用 authz</span></span>
<span class="line"><span>  -&gt; authz allow 后注入普通上下文与 x-firefly-authz-sign</span></span>
<span class="line"><span>  -&gt; go-micro middleware 构造 service.Context</span></span>
<span class="line"><span>  -&gt; Service / Biz / Data</span></span></code></pre></div><p>这条链路里，业务服务不直接管理注册中心 SDK，不自己做实例发现和负载均衡，也不从 gRPC 描述反推 HTTP route。服务能力以 <code>gateway.manifest.json</code> 为准。</p><h2 id="组件职责" tabindex="-1">组件职责 <a class="header-anchor" href="#组件职责" aria-label="Permalink to &quot;组件职责&quot;">​</a></h2><ul><li><code>go-layout</code>：Go 业务服务模板，负责 Service / Biz / Data 分层、Wire 装配、启动配置、gRPC 入口、management 端口和示例依赖。</li><li><code>go-micro</code>：公共上下文、中间件、invocation、配置契约、telemetry、service authority 管理等基础库。</li><li><code>go-consul/agent</code>：裸机业务服务与本机 <code>sidecar-agent</code> 的桥接层，读取 manifest 并执行 register / drain / deregister / watch。</li><li><code>sidecar-agent</code>：裸机本机控制面，写 Consul service 与 route document，维护本机 Envoy xDS、健康探测和恢复视图。</li><li><code>CoreDNS</code>：节点级 DNS 基础设施，解析 <code>*.svc.cluster.local</code> 到本机 mesh VIP；透明导流由 nftables 和 Envoy 承担。</li><li><code>api-gateway</code>：north-south 入口网关控制面，消费 Consul route document、健康 endpoint 与 namespace descriptor current，生成入口 Envoy xDS。</li><li><code>authz</code>：Envoy ext_authz 数据面授权服务，校验 Firefly authority，执行 Casbin 判定，签发短 TTL <code>x-firefly-authz-sign</code>。</li></ul><h2 id="身份入口" tabindex="-1">身份入口 <a class="header-anchor" href="#身份入口" aria-label="Permalink to &quot;身份入口&quot;">​</a></h2><p>Firefly current 身份入口只有：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>x-firefly-user-authority</span></span>
<span class="line"><span>x-firefly-service-authority</span></span>
<span class="line"><span>x-firefly-authz-sign</span></span></code></pre></div><p><code>Authorization</code> 不再作为 Firefly 身份入口。OTel / W3C Trace Context 是追踪主线，默认传播 <code>traceparent</code>、<code>tracestate</code> 和 <code>baggage</code>；<code>x-request-id</code> 只作为 Envoy 或日志关联 ID。</p><p>权限匹配的核心元组是：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>invoke_app_id + method + path + target_app_id</span></span></code></pre></div><p>route document 中的 <code>app_id</code> 表示 route 所属服务应用，authz 内部再映射为 <code>target_app_id</code>。</p><h2 id="不再推荐" tabindex="-1">不再推荐 <a class="header-anchor" href="#不再推荐" aria-label="Permalink to &quot;不再推荐&quot;">​</a></h2><p>以下内容只应出现在历史文档或迁移说明中，不应作为新项目入口：</p><ul><li>业务服务直接依赖注册中心 SDK 做 discovery / LB。</li><li>从 <code>RawServices</code>、<code>grpc.ServiceDesc</code> 或手写清单推导 HTTP route。</li><li>使用 <code>Authorization</code>、<code>x-firefly-authz-context</code> 或旧 <code>authz-context</code> 作为 Firefly 身份主线。</li><li>把 Config 服务作为业务服务高频运行期配置读取代理。</li><li>在 <code>bootstrap.json</code> 中恢复旧 <code>micro</code>、<code>gateway</code>、<code>data_conf_file</code> 配置结构。</li></ul>`,22)]))}const g=a(o,[["render",i]]);export{h as __pageData,g as default};
